import java.util.List;

public int countConvertibleWords(List<String> startWords, List<String> targetWords) {
    int count = 0;
    for (String target : targetWords) {
        for (String start : startWords) {
            if (start.length() + 1 == target.length() && target.startsWith(start)) {
                count++;
                break;
            }
        }
    }
    return count;
}
```

